interfaces.interface:
// Existing props (backward compatible)
user: UserPresenceData;
onClick?: (userId: string) => void;
// New props for Story 3.3
isSpeaking?: boolean;
isPresenting?: boolean;
isMuted?: boolean;
size?: 'sm' | 'md' | 'lg'; // sm=28px, md=36px (default), lg=48px

users: UserPresenceData[];
max?: number; // Story 3.3: Default 4 for orbit, 8 for cinema
size?: 'sm' | 'md' | 'lg' | 'xl';
className?: string;
onUserClick?: (userId: string) => void;
showEmpty?: boolean;
emptyText?: string;

id: string;
displayName: string;
avatarUrl?: string;
status?: 'online' | 'away' | 'busy' | 'offline';
currentSpaceId?: string;
// ... additional fields
